const puppeteer = require('puppeteer');
const { job_url, company, role } = $node['Webhook: Apply Request'].json.body;
const profile = $node['Supabase: Hydrate Profile'].json;

async function run() {
  const browser = await puppeteer.launch({ 
    headless: true, 
    args: ['--no-sandbox', '--disable-setuid-sandbox'] 
  });
  const page = await browser.newPage();

  try {
    await page.goto(job_url, { waitUntil: 'networkidle2', timeout: 60000 });

    // HUMAN-LIKE DELAY
    await new Promise(r => setTimeout(r, Math.random() * 2000 + 1000));

    // NEURAL MAPPING: Try to find common input fields
    const inputs = await page.$$('input');
    for (const input of inputs) {
      const name = (await (await input.getProperty('name')).jsonValue()).toLowerCase();
      const placeholder = (await (await input.getProperty('placeholder')).jsonValue()).toLowerCase();

      if (name.includes('name') || placeholder.includes('name')) {
        await input.type(profile.name || 'DigyNex Expert', { delay: 100 });
      }
      if (name.includes('email') || placeholder.includes('email')) {
        await input.type(profile.email, { delay: 100 });
      }
    }

    // UPLOAD CV
    const fileInput = await page.$('input[type="file"]');
    if (fileInput) {
      // In n8n, binary data from previous node is available via $binary
      // We would save it to disk first in a real script, but here we simulate the path
      await fileInput.uploadFile('/tmp/specimen.pdf');
    }

    // SUBMIT
    await page.click('button[type="submit"], input[type="submit"]');
    await new Promise(r => setTimeout(r, 5000));

    return {
      status: 'success',
      company,
      role,
      url: job_url,
      timestamp: new Date().toISOString()
    };
  } catch (err) {
    return {
      status: 'error',
      message: err.message,
      company,
      role
    };
  } finally {
    await browser.close();
  }
}

return run();
